@app.route("/")
def index():
    user = session.get("user")
    if not user:
        return redirect(url_for("login"))
    return make_response(
        "<h1>Admin Dashboard</h1>"
        "<p>Authenticated</p>"
        f"<pre>{json.dumps(user, indent=2)}</pre>"
        '<p><a href="/logout">Logout</a></p>',
        200,
        {"Content-Type": "text/html; charset=utf-8"},
    )


@app.route("/login")
def login():
    if not CLIENT_ID:
        abort(500, "Missing OIDC_CLIENT_ID")
    if not REDIRECT_URI:
        abort(500, "Missing OIDC_REDIRECT_URI")

    if not ALLOW_INSECURE_NO_NONCE:
        abort(500, "Refusing to run without nonce. Set ALLOW_INSECURE_NO_NONCE=true to override (NOT RECOMMENDED).")

    state = secrets.token_urlsafe(24)
    session["oidc_state"] = state
    session.permanent = True

    return redirect(_build_authorize_url(state))


